{
  "name": "FinanceFlow AI",
  "description": "Uma plataforma inteligente para organizar e analisar extratos bancários, com insights automáticos via Gemini AI e visualizações detalhadas de gastos."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Transaction {
  id: string;
  date: string;
  description: string;
  amount: number;
  category: string;
  type: 'income' | 'expense';
}

export interface AIInsights {
  summary: string;
  topCategories: { category: string; total: number }[];
  savingTips: string[];
  anomalies: string[];
}

export enum AppState {
  EMPTY = 'EMPTY',
  LOADING = 'LOADING',
  READY = 'READY',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { Transaction, AIInsights } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeTransactions = async (transactions: Transaction[]): Promise<AIInsights> => {
  const transactionData = transactions.map(t => ({
    date: t.date,
    desc: t.description,
    val: t.amount,
    cat: t.category
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analise o seguinte extrato bancário e forneça insights financeiros. 
    Dados: ${JSON.stringify(transactionData)}

    Por favor, retorne no formato JSON com:
    1. "summary": Um breve resumo do mês financeiro.
    2. "topCategories": Um array de objetos {category, total} com as 3 categorias onde mais se gastou.
    3. "savingTips": Um array com 3 dicas personalizadas para economizar baseadas nos dados.
    4. "anomalies": Um array com possíveis gastos estranhos ou assinaturas esquecidas.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          topCategories: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                category: { type: Type.STRING },
                total: { type: Type.NUMBER }
              },
              required: ["category", "total"]
            }
          },
          savingTips: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          anomalies: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["summary", "topCategories", "savingTips", "anomalies"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}') as AIInsights;
  } catch (error) {
    console.error("Erro ao processar insights da AI:", error);
    throw new Error("Falha na análise da AI");
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, AppState, AIInsights } from './types';
import { analyzeTransactions } from './services/geminiService';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import ImportModal from './components/ImportModal';
import AIInsightsPanel from './components/AIInsightsPanel';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.EMPTY);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [insights, setInsights] = useState<AIInsights | null>(null);
  const [loadingInsights, setLoadingInsights] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('ff_transactions');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.length > 0) {
        setTransactions(parsed);
        setAppState(AppState.READY);
      }
    }
  }, []);

  // Save to local storage when transactions change
  useEffect(() => {
    if (transactions.length > 0) {
      localStorage.setItem('ff_transactions', JSON.stringify(transactions));
    }
  }, [transactions]);

  const handleImportData = (newData: Transaction[]) => {
    setTransactions(newData);
    setAppState(AppState.READY);
    setIsImportModalOpen(false);
    setInsights(null); // Reset insights for new data
  };

  const generateAIInsights = async () => {
    if (transactions.length === 0) return;
    setLoadingInsights(true);
    try {
      const result = await analyzeTransactions(transactions);
      setInsights(result);
    } catch (error) {
      console.error(error);
      alert("Erro ao gerar insights. Verifique sua conexão ou API Key.");
    } finally {
      setLoadingInsights(false);
    }
  };

  const handleReset = () => {
    if (confirm("Tem certeza que deseja apagar todos os dados?")) {
      setTransactions([]);
      setAppState(AppState.EMPTY);
      setInsights(null);
      localStorage.removeItem('ff_transactions');
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-20 md:pb-0">
      <Header 
        onOpenImport={() => setIsImportModalOpen(true)} 
        onReset={handleReset}
        hasData={transactions.length > 0}
      />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        {appState === AppState.EMPTY ? (
          <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-6">
            <div className="w-24 h-24 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 text-4xl">
              <i className="fas fa-file-invoice-dollar"></i>
            </div>
            <h2 className="text-3xl font-bold text-slate-800">Seu Organizador Financeiro Inteligente</h2>
            <p className="text-slate-500 max-w-md mx-auto">
              Importe seus extratos bancários (CSV ou Link de Planilha) e deixe nossa IA categorizar seus gastos e fornecer insights valiosos.
            </p>
            <button 
              onClick={() => setIsImportModalOpen(true)}
              className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-semibold shadow-lg transition-all flex items-center gap-2"
            >
              <i className="fas fa-plus"></i> Começar Agora
            </button>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in duration-500">
            <Dashboard transactions={transactions} />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2">
                <TransactionList transactions={transactions} />
              </div>
              <div className="lg:col-span-1">
                <AIInsightsPanel 
                  insights={insights} 
                  isLoading={loadingInsights} 
                  onGenerate={generateAIInsights}
                  hasTransactions={transactions.length > 0}
                />
              </div>
            </div>
          </div>
        )}
      </main>

      {isImportModalOpen && (
        <ImportModal 
          onClose={() => setIsImportModalOpen(false)} 
          onImport={handleImportData} 
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';

interface HeaderProps {
  onOpenImport: () => void;
  onReset: () => void;
  hasData: boolean;
}

const Header: React.FC<HeaderProps> = ({ onOpenImport, onReset, hasData }) => {
  return (
    <header className="bg-white border-b border-slate-200 sticky top-0 z-30 shadow-sm">
      <div className="container mx-auto px-4 h-16 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white text-lg">
            <i className="fas fa-chart-line"></i>
          </div>
          <h1 className="text-xl font-bold text-slate-900 tracking-tight hidden sm:block">
            Finance<span className="text-indigo-600">Flow</span> AI
          </h1>
        </div>

        <div className="flex items-center gap-3">
          {hasData && (
            <button 
              onClick={onReset}
              className="text-slate-400 hover:text-red-500 p-2 transition-colors rounded-lg hover:bg-red-50"
              title="Limpar todos os dados"
            >
              <i className="fas fa-trash-alt"></i>
            </button>
          )}
          <button 
            onClick={onOpenImport}
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg font-medium transition-all shadow-sm"
          >
            <i className="fas fa-file-import"></i>
            <span className="hidden xs:inline">Importar</span>
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useMemo } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid } from 'recharts';
import { Transaction } from '../types';

interface DashboardProps {
  transactions: Transaction[];
}

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const income = transactions.filter(t => t.type === 'income').reduce((sum, t) => sum + t.amount, 0);
    const expenses = transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + Math.abs(t.amount), 0);
    const balance = income - expenses;

    // Group by category for Pie Chart
    const categoryMap: Record<string, number> = {};
    transactions.filter(t => t.type === 'expense').forEach(t => {
      const cat = t.category || 'Outros';
      categoryMap[cat] = (categoryMap[cat] || 0) + Math.abs(t.amount);
    });

    const pieData = Object.entries(categoryMap).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);

    // Group by month for Bar Chart (Simplified to last few months or current data)
    const monthData = transactions.reduce((acc: any, t) => {
      const month = new Date(t.date).toLocaleString('default', { month: 'short' });
      if (!acc[month]) acc[month] = { month, income: 0, expense: 0 };
      if (t.type === 'income') acc[month].income += t.amount;
      else acc[month].expense += Math.abs(t.amount);
      return acc;
    }, {});

    const barData = Object.values(monthData);

    return { income, expenses, balance, pieData, barData };
  }, [transactions]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  return (
    <div className="space-y-6">
      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <p className="text-sm font-medium text-slate-500 uppercase">Receitas</p>
          <p className="text-2xl font-bold text-emerald-600 mt-1">{formatCurrency(stats.income)}</p>
          <div className="mt-4 flex items-center text-xs text-emerald-500 bg-emerald-50 px-2 py-1 rounded w-fit">
            <i className="fas fa-arrow-up mr-1"></i> Entradas totais
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <p className="text-sm font-medium text-slate-500 uppercase">Despesas</p>
          <p className="text-2xl font-bold text-rose-600 mt-1">{formatCurrency(stats.expenses)}</p>
          <div className="mt-4 flex items-center text-xs text-rose-500 bg-rose-50 px-2 py-1 rounded w-fit">
            <i className="fas fa-arrow-down mr-1"></i> Saídas totais
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <p className="text-sm font-medium text-slate-500 uppercase">Saldo Final</p>
          <p className={`text-2xl font-bold mt-1 ${stats.balance >= 0 ? 'text-indigo-600' : 'text-red-600'}`}>
            {formatCurrency(stats.balance)}
          </p>
          <div className={`mt-4 flex items-center text-xs px-2 py-1 rounded w-fit ${stats.balance >= 0 ? 'text-indigo-500 bg-indigo-50' : 'text-red-500 bg-red-50'}`}>
             <i className="fas fa-wallet mr-1"></i> Disponível
          </div>
        </div>
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-semibold text-slate-800 mb-6">Gastos por Categoria</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={stats.pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {stats.pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                  formatter={(value: number) => formatCurrency(value)}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 flex flex-wrap gap-x-4 gap-y-2">
            {stats.pieData.slice(0, 4).map((entry, idx) => (
              <div key={idx} className="flex items-center gap-1.5 text-xs text-slate-600">
                <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></div>
                {entry.name}
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-semibold text-slate-800 mb-6">Fluxo de Caixa Mensal</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.barData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} hide />
                <Tooltip 
                  formatter={(value: number) => formatCurrency(value)}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="income" fill="#10b981" radius={[4, 4, 0, 0]} barSize={32} name="Receita" />
                <Bar dataKey="expense" fill="#ef4444" radius={[4, 4, 0, 0]} barSize={32} name="Despesa" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Transaction } from '../types';

interface TransactionListProps {
  transactions: Transaction[];
}

const TransactionList: React.FC<TransactionListProps> = ({ transactions }) => {
  const [filter, setFilter] = useState('');

  const filtered = transactions.filter(t => 
    t.description.toLowerCase().includes(filter.toLowerCase()) ||
    t.category.toLowerCase().includes(filter.toLowerCase())
  ).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full">
      <div className="p-6 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <h3 className="text-lg font-semibold text-slate-800">Transações</h3>
        <div className="relative">
          <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm"></i>
          <input 
            type="text" 
            placeholder="Buscar transações..."
            className="pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 w-full sm:w-64"
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto flex-grow max-h-[600px]">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-slate-500 sticky top-0">
            <tr>
              <th className="px-6 py-4 font-medium uppercase tracking-wider">Data</th>
              <th className="px-6 py-4 font-medium uppercase tracking-wider">Descrição</th>
              <th className="px-6 py-4 font-medium uppercase tracking-wider">Categoria</th>
              <th className="px-6 py-4 font-medium uppercase tracking-wider text-right">Valor</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filtered.length > 0 ? filtered.map((t) => (
              <tr key={t.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 whitespace-nowrap text-slate-500">
                  {new Date(t.date).toLocaleDateString('pt-BR')}
                </td>
                <td className="px-6 py-4 font-medium text-slate-900">
                  {t.description}
                </td>
                <td className="px-6 py-4">
                  <span className="px-2.5 py-1 bg-slate-100 text-slate-600 rounded-full text-xs font-medium">
                    {t.category}
                  </span>
                </td>
                <td className={`px-6 py-4 text-right font-bold ${t.type === 'income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                  {t.type === 'income' ? '+' : '-'} {formatCurrency(Math.abs(t.amount))}
                </td>
              </tr>
            )) : (
              <tr>
                <td colSpan={4} className="px-6 py-12 text-center text-slate-400">
                  Nenhuma transação encontrada.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TransactionList;

import React, { useState } from 'react';
import { Transaction } from '../types';

interface ImportModalProps {
  onClose: () => void;
  onImport: (data: Transaction[]) => void;
}

const ImportModal: React.FC<ImportModalProps> = ({ onClose, onImport }) => {
  const [activeTab, setActiveTab] = useState<'csv' | 'link'>('csv');
  const [sheetUrl, setSheetUrl] = useState('');
  const [loading, setLoading] = useState(false);

  const processCSV = (text: string) => {
    const lines = text.split('\n');
    const result: Transaction[] = [];

    // Simple CSV parser: Data, Descrição, Valor, Categoria
    // Expected format with headers or without
    for (let i = 1; i < lines.length; i++) {
      const line = lines[i].trim();
      if (!line) continue;

      const parts = line.split(/[,;]/);
      if (parts.length < 3) continue;

      const dateStr = parts[0]?.trim();
      const desc = parts[1]?.trim();
      const valStr = parts[2]?.trim().replace(/[R$\s]/g, '').replace(',', '.');
      const cat = parts[3]?.trim() || 'Outros';

      const amount = parseFloat(valStr);
      if (isNaN(amount)) continue;

      result.push({
        id: Math.random().toString(36).substr(2, 9),
        date: dateStr,
        description: desc,
        amount: amount,
        category: cat,
        type: amount >= 0 ? 'income' : 'expense'
      });
    }
    return result;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const data = processCSV(text);
      onImport(data);
      setLoading(false);
    };
    reader.readAsText(file);
  };

  const handleLinkImport = async () => {
    if (!sheetUrl) return;
    setLoading(true);

    // Simple logic: if it's a Google Sheet link, try to fetch as CSV
    try {
      let fetchUrl = sheetUrl;
      if (sheetUrl.includes('docs.google.com/spreadsheets')) {
        const idMatch = sheetUrl.match(/\/d\/(.+?)\//);
        if (idMatch) {
          fetchUrl = `https://docs.google.com/spreadsheets/d/${idMatch[1]}/export?format=csv`;
        }
      }

      const response = await fetch(fetchUrl);
      if (!response.ok) throw new Error("Falha ao baixar arquivo");
      const text = await response.text();
      const data = processCSV(text);
      if (data.length === 0) throw new Error("Nenhum dado válido encontrado");
      onImport(data);
    } catch (err) {
      alert("Erro ao importar: Verifique se o link é público e no formato correto.");
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between">
          <h3 className="text-xl font-bold text-slate-800">Importar Dados</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
            <i className="fas fa-times text-xl"></i>
          </button>
        </div>

        <div className="p-6">
          <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
            <button 
              onClick={() => setActiveTab('csv')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'csv' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <i className="fas fa-file-csv mr-2"></i> CSV Upload
            </button>
            <button 
              onClick={() => setActiveTab('link')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'link' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <i className="fas fa-link mr-2"></i> Link Planilha
            </button>
          </div>

          {activeTab === 'csv' ? (
            <div className="space-y-4">
              <div className="border-2 border-dashed border-slate-200 rounded-2xl p-8 flex flex-col items-center justify-center text-center hover:border-indigo-300 transition-colors cursor-pointer relative">
                <input 
                  type="file" 
                  accept=".csv" 
                  onChange={handleFileUpload}
                  className="absolute inset-0 opacity-0 cursor-pointer"
                  disabled={loading}
                />
                <div className="w-12 h-12 bg-indigo-50 text-indigo-500 rounded-full flex items-center justify-center mb-4 text-xl">
                  <i className="fas fa-cloud-upload-alt"></i>
                </div>
                <p className="font-semibold text-slate-700">Arraste ou clique para enviar</p>
                <p className="text-sm text-slate-400 mt-1">Apenas arquivos .csv suportados</p>
              </div>
              <div className="bg-blue-50 p-4 rounded-xl border border-blue-100">
                <p className="text-xs text-blue-700 flex gap-2">
                  <i className="fas fa-info-circle mt-0.5"></i>
                  <span>O arquivo deve conter as colunas: <strong>Data, Descrição, Valor, Categoria</strong>.</span>
                </p>
              </div>
            </div>
          ) : (
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1.5">Link Público (Google Sheets)</label>
                <input 
                  type="url" 
                  placeholder="https://docs.google.com/spreadsheets/d/..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500/20"
                  value={sheetUrl}
                  onChange={(e) => setSheetUrl(e.target.value)}
                />
              </div>
