const ImportModal: React.FC<ImportModalProps> = ({ onClose, onImport }) => {
  const [activeTab, setActiveTab] = useState<'csv' | 'link'>('csv');
  const [sheetUrl, setSheetUrl] = useState('');
  const [loading, setLoading] = useState(false);

  // Helper to clean and parse numerical values
  const parseValue = (valStr: string): number => {
    if (!valStr) return NaN;
    let clean = valStr.replace(/[R$\s"]/g, '').trim();

    // Handle Brazilian format: 1.234,56 or 1234,56
    if (clean.includes(',') && clean.includes('.')) {
      clean = clean.replace(/\./g, '').replace(',', '.');
    } else if (clean.includes(',')) {
      clean = clean.replace(',', '.');
    }
    return parseFloat(clean);
  };

  const processCSV = (text: string) => {
    const rawLines = text.split(/\r?\n/).map(l => l.trim()).filter(line => line.length > 0);
    if (rawLines.length === 0) return [];

    // Detect separator from the first non-empty line
    const separator = rawLines[0].includes(';') ? ';' : ',';

    // Scan the first few lines to find a header row
    let headerRowIdx = -1;
    let indices = { date: 0, desc: 1, val: 2, cat: 3 };
    let foundHeaders = false;

    // Look for headers in the first 15 lines
    for (let i = 0; i < Math.min(rawLines.length, 15); i++) {
      const parts = rawLines[i].split(separator).map(p => p.toLowerCase().trim().replace(/^"|"$/g, ''));
      const hasDate = parts.some(p => p.includes('data'));
      const hasVal = parts.some(p => p.includes('valor') || p.includes('montante') || p.includes('pago'));
      const hasDesc = parts.some(p => p.includes('desc') || p.includes('historico') || p.includes('detalhe'));

      if (hasDate && (hasVal || hasDesc)) {
        headerRowIdx = i;
        indices.date = parts.findIndex(p => p.includes('data'));
        indices.desc = parts.findIndex(p => p.includes('desc') || p.includes('historico') || p.includes('detalhe'));
        indices.val = parts.findIndex(p => p.includes('valor') || p.includes('montante') || p.includes('pago') || p.includes('recebido'));
        indices.cat = parts.findIndex(p => p.includes('cat'));

        // Ensure we have at least date, desc, and val
        if (indices.date !== -1 && indices.desc !== -1 && indices.val !== -1) {
          foundHeaders = true;
          break;
        }
      }
    }

    const startIdx = foundHeaders ? headerRowIdx + 1 : 0;
    const result: Transaction[] = [];

    for (let i = startIdx; i < rawLines.length; i++) {
      const line = rawLines[i].trim();
      const parts = line.split(separator).map(p => p.replace(/^"|"$/g, '').trim());

      // Basic validation
      if (parts.length <= Math.max(indices.date, indices.desc, indices.val)) continue;

      const dateStr = parts[indices.date];
      const desc = parts[indices.desc];
      const amount = parseValue(parts[indices.val]);
      const cat = (indices.cat !== -1 ? parts[indices.cat] : 'Outros') || 'Outros';

      // Skip rows with invalid data
      if (isNaN(amount) || !dateStr || !desc || dateStr.toLowerCase().includes('data')) continue;

      result.push({
        id: Math.random().toString(36).substr(2, 9),
        date: dateStr,
        description: desc,
        amount: amount,
        category: cat,
        type: amount >= 0 ? 'income' : 'expense'
      });
    }

    return result;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const data = processCSV(text);
      if (data.length > 0) {
        onImport(data);
      } else {
        alert("Não conseguimos identificar os dados. Verifique se o CSV contém as colunas 'Data', 'Descrição' e 'Valor'.");
      }
      setLoading(false);
    };
    reader.onerror = () => {
      alert("Erro ao ler o arquivo.");
      setLoading(false);
    };
    reader.readAsText(file);
  };

  const handleLinkImport = async () => {
    if (!sheetUrl) return;
    setLoading(true);

    try {
      let fetchUrl = sheetUrl;
      // Handle Google Sheets sharing link
      if (sheetUrl.includes('docs.google.com/spreadsheets')) {
        const idMatch = sheetUrl.match(/\/d\/(.+?)(\/|$)/);
        if (idMatch) {
          fetchUrl = `https://docs.google.com/spreadsheets/d/${idMatch[1]}/export?format=csv`;
        }
      }

      const response = await fetch(fetchUrl);
      if (!response.ok) throw new Error("O link parece não ser público ou acessível.");

      const text = await response.text();
      const data = processCSV(text);

      if (data.length === 0) {
        throw new Error("Não encontramos transações válidas. Verifique os títulos das colunas na sua planilha.");
      }

      onImport(data);
    } catch (err: any) {
      alert(`Erro ao importar: ${err.message}`);
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between">
          <h3 className="text-xl font-bold text-slate-800">Importar Dados</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2">
            <i className="fas fa-times text-xl"></i>
          </button>
        </div>

        <div className="p-6">
          <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
            <button 
              onClick={() => setActiveTab('csv')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'csv' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <i className="fas fa-file-csv mr-2"></i> CSV Upload
            </button>
            <button 
              onClick={() => setActiveTab('link')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'link' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              <i className="fas fa-link mr-2"></i> Link Planilha
            </button>
          </div>

          {activeTab === 'csv' ? (
