import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, AppState, AIInsights, SourceKey, MonthData } from './types';
import { analyzeTransactions } from './services/geminiService';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import SourceManager from './components/SourceManager';
import AIInsightsPanel from './components/AIInsightsPanel';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.EMPTY);
  const [currentMonthId, setCurrentMonthId] = useState(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
  });

  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isSourceManagerOpen, setIsSourceManagerOpen] = useState(false);
  const [insights, setInsights] = useState<AIInsights | null>(null);
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [syncing, setSyncing] = useState(false);

  // Carrega links salvos para o mês atual
  const [monthConfigs, setMonthConfigs] = useState<Record<string, Record<SourceKey, string>>>(() => {
    const saved = localStorage.getItem('ff_month_configs');
    return saved ? JSON.parse(saved) : {};
  });

  useEffect(() => {
    localStorage.setItem('ff_month_configs', JSON.stringify(monthConfigs));
  }, [monthConfigs]);

  const currentSources = useMemo(() => {
    return monthConfigs[currentMonthId] || {
      nubank_pj_pix: '',
      nubank_pf_pix: '',
      nubank_cc: '',
      picpay_pf_pix: '',
      picpay_pj_pix: ''
    } as Record<SourceKey, string>;
  }, [monthConfigs, currentMonthId]);

  const handleUpdateSources = (newSources: Record<SourceKey, string>) => {
    setMonthConfigs(prev => ({
      ...prev,
      [currentMonthId]: newSources
    }));
  };

  const parseValue = (valStr: string): number => {
    if (!valStr) return NaN;
    let clean = valStr.replace(/[R$\s"]/g, '').trim();
    if (clean.includes(',') && clean.includes('.')) {
      clean = clean.replace(/\./g, '').replace(',', '.');
    } else if (clean.includes(',')) {
      clean = clean.replace(',', '.');
    }
    return parseFloat(clean);
  };

  const processCSV = (text: string, source: SourceKey): Transaction[] => {
    const lines = text.split(/\r?\n/).filter(l => l.trim().length > 0);
    const result: Transaction[] = [];
    const separator = lines[0].includes(';') ? ';' : ',';

    // User requested: A: Data, B: Valor, C: Descrição
    // We skip the first line if it looks like a header
    const firstLineParts = lines[0].split(separator);
    const hasHeader = isNaN(parseValue(firstLineParts[1]));
    const startIdx = hasHeader ? 1 : 0;

    for (let i = startIdx; i < lines.length; i++) {
      const parts = lines[i].split(separator).map(p => p.replace(/^"|"$/g, '').trim());
      if (parts.length < 3) continue;

      const dateStr = parts[0];
      const amount = parseValue(parts[1]);
      const desc = parts[2];
      const cat = parts[3] || 'Geral';

      if (isNaN(amount) || !dateStr || !desc) continue;

      result.push({
        id: `${source}-${Math.random().toString(36).substr(2, 5)}`,
        date: dateStr,
        description: desc,
        amount: amount,
        category: cat,
        type: amount >= 0 ? 'income' : 'expense',
        source: source
      });
    }
    return result;
  };

  const fetchAllData = async () => {
    setSyncing(true);
    setAppState(AppState.LOADING);
    let allTransactions: Transaction[] = [];

    // Explicitly cast entries to [SourceKey, string][] to ensure types are correctly handled during filter and iteration
    const activeSources = (Object.entries(currentSources) as [SourceKey, string][]).filter(([_, url]) => url.startsWith('http'));

    if (activeSources.length === 0) {
      setTransactions([]);
      setAppState(AppState.EMPTY);
      setSyncing(false);
      return;
    }

    for (const [key, url] of activeSources) {
      try {
        let fetchUrl: string = url;
        if (url.includes('docs.google.com/spreadsheets')) {
          const idMatch = url.match(/\/d\/(.+?)(\/|$)/);
          if (idMatch) fetchUrl = `https://docs.google.com/spreadsheets/d/${idMatch[1]}/export?format=csv`;
        }

        const response = await fetch(fetchUrl);
        if (response.ok) {
          const text = await response.text();
          const sourceTransactions = processCSV(text, key);
          allTransactions = [...allTransactions, ...sourceTransactions];
        }
      } catch (err) {
        console.error(`Erro ao carregar fonte ${key}:`, err);
      }
    }

    setTransactions(allTransactions);
    setAppState(allTransactions.length > 0 ? AppState.READY : AppState.EMPTY);
    setSyncing(false);
    setInsights(null);
  };

  // Sync when sources change or month changes
  useEffect(() => {
    fetchAllData();
  }, [currentMonthId]);

  const generateAIInsights = async () => {
    if (transactions.length === 0) return;
    setLoadingInsights(true);
    try {
      const result = await analyzeTransactions(transactions);
      setInsights(result);
    } catch (error) {
      alert("Erro na análise. Verifique se a API Key está configurada.");
    } finally {
      setLoadingInsights(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header 
        currentMonthId={currentMonthId}
        onMonthChange={setCurrentMonthId}
        onOpenSources={() => setIsSourceManagerOpen(true)}
        isSyncing={syncing}
        onRefresh={fetchAllData}
      />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        {appState === AppState.EMPTY && !syncing ? (
          <div className="flex flex-col items-center justify-center min-h-[50vh] text-center space-y-6">
            <div className="w-20 h-20 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600 text-3xl">
              <i className="fas fa-plug"></i>
            </div>
            <h2 className="text-2xl font-bold text-slate-800">Nenhuma fonte configurada para este mês</h2>
            <p className="text-slate-500 max-w-sm mx-auto">
              Adicione os links das suas planilhas do Google para o mês de {currentMonthId} para começar.
            </p>
            <button 
              onClick={() => setIsSourceManagerOpen(true)}
              className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-semibold shadow-lg hover:bg-indigo-700 transition-all"
            >
              Configurar Planilhas
            </button>
          </div>
        ) : appState === AppState.LOADING ? (
          <div className="flex flex-col items-center justify-center min-h-[50vh]">
            <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-600 border-t-transparent"></div>
            <p className="mt-4 text-slate-500 font-medium">Sincronizando extratos...</p>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in duration-500">
            <Dashboard transactions={transactions} />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2">
                <TransactionList transactions={transactions} />
              </div>
              <div className="lg:col-span-1">
                <AIInsightsPanel 
                  insights={insights} 
                  isLoading={loadingInsights} 
                  onGenerate={generateAIInsights}
                  hasTransactions={transactions.length > 0}
                />
              </div>
            </div>
          </div>
        )}
      </main>

      {isSourceManagerOpen && (
        <SourceManager 
          onClose={() => setIsSourceManagerOpen(false)} 
          currentSources={currentSources}
          onUpdate={handleUpdateSources}
          onSync={fetchAllData}
          monthLabel={currentMonthId}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Transaction, SourceKey } from '../types';

interface ImportModalProps {
  onClose: () => void;
  onImport: (data: Transaction[]) => void;
}

const ImportModal: React.FC<ImportModalProps> = ({ onClose, onImport }) => {
  const [activeTab, setActiveTab] = useState<'csv' | 'link'>('csv');
  const [sheetUrl, setSheetUrl] = useState('');
  const [loading, setLoading] = useState(false);

  // Helper to clean and parse numerical values
  const parseValue = (valStr: string): number => {
    if (!valStr) return NaN;
    // Remove currency symbols, spaces, and handle both . and , formats
    let clean = valStr.replace(/[R$\s"]/g, '').trim();

    // Handle Brazilian format: 1.234,56 or 1234,56
    if (clean.includes(',') && clean.includes('.')) {
      // 1.234,56 -> 1234.56
      clean = clean.replace(/\./g, '').replace(',', '.');
    } else if (clean.includes(',')) {
      // 1234,56 -> 1234.56
      clean = clean.replace(',', '.');
    }
    return parseFloat(clean);
  };

  const processCSV = (text: string) => {
    const rawLines = text.split(/\r?\n/).map(l => l.trim()).filter(line => line.length > 0);
    if (rawLines.length === 0) return [];

    // Detect separator from the first non-empty line
    const separator = rawLines[0].includes(';') ? ';' : ',';

    // Default indices based on user specification: 
    // Coluna A (0) = Data, Coluna B (1) = Valor, Coluna C (2) = Descrição
    let indices = { date: 0, val: 1, desc: 2, cat: 3 };
    let headerRowIdx = -1;
    let foundHeaders = false;

    // Scan the first few lines to see if there's an explicit header row
    for (let i = 0; i < Math.min(rawLines.length, 10); i++) {
      const parts = rawLines[i].split(separator).map(p => p.toLowerCase().trim().replace(/^"|"$/g, ''));

      const dIdx = parts.findIndex(p => p.includes('data'));
      const vIdx = parts.findIndex(p => p.includes('valor') || p.includes('montante') || p.includes('pago') || p.includes('recebido') || p.includes('quantia'));
      const deIdx = parts.findIndex(p => p.includes('desc') || p.includes('historico') || p.includes('detalhe') || p.includes('lançamento'));
      const cIdx = parts.findIndex(p => p.includes('cat'));

      // If we find at least Data and (Valor or Descrição), consider it a header row
      if (dIdx !== -1 && (vIdx !== -1 || deIdx !== -1)) {
        headerRowIdx = i;
        indices.date = dIdx;
        indices.val = vIdx !== -1 ? vIdx : indices.val;
        indices.desc = deIdx !== -1 ? deIdx : indices.desc;
        indices.cat = cIdx !== -1 ? cIdx : indices.cat;
        foundHeaders = true;
        break;
      }
    }

    // If no header found, we start from row 0 using the user's A=Date, B=Val, C=Desc mapping
    // If header found, we start from the row after the header
    const startIdx = foundHeaders ? headerRowIdx + 1 : 0;
    const result: Transaction[] = [];

    for (let i = startIdx; i < rawLines.length; i++) {
      const line = rawLines[i].trim();
      const parts = line.split(separator).map(p => p.replace(/^"|"$/g, '').trim());

      // Basic validation: must have at least the columns we need
      const maxNeededIdx = Math.max(indices.date, indices.val, indices.desc);
      if (parts.length <= maxNeededIdx) continue;

      const dateStr = parts[indices.date];
      const amount = parseValue(parts[indices.val]);
      const desc = parts[indices.desc];
      const cat = (indices.cat !== -1 && parts[indices.cat]) ? parts[indices.cat] : 'Geral';

      // Validation check
      if (isNaN(amount) || !dateStr || !desc) continue;

      // Skip if the "date" looks like a header (e.g. "Data")
      if (dateStr.toLowerCase().includes('data')) continue;

      // Add a default source key to satisfy the Transaction interface
      result.push({
        id: Math.random().toString(36).substr(2, 9),
        date: dateStr,
        description: desc,
        amount: amount,
        category: cat,
        type: amount >= 0 ? 'income' : 'expense',
        source: 'nubank_pf_pix' as SourceKey
      });
    }

    return result;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setLoading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const data = processCSV(text);
      if (data.length > 0) {
        onImport(data);
      } else {
        alert("Não conseguimos identificar os dados. Verifique se o CSV está no formato: Coluna A (Data), Coluna B (Valor), Coluna C (Descrição).");
      }
      setLoading(false);
    };
    reader.onerror = () => {
      alert("Erro ao ler o arquivo.");
      setLoading(false);
    };
    reader.readAsText(file);
  };

  const handleLinkImport = async () => {
    if (!sheetUrl) return;
    setLoading(true);

    try {
      let fetchUrl = sheetUrl;
      if (sheetUrl.includes('docs.google.com/spreadsheets')) {
        const idMatch = sheetUrl.match(/\/d\/(.+?)(\/|$)/);
        if (idMatch) {
          fetchUrl = `https://docs.google.com/spreadsheets/d/${idMatch[1]}/export?format=csv`;
        }
      }

      const response = await fetch(fetchUrl);
      if (!response.ok) throw new Error("O link parece não ser público ou acessível.");

      const text = await response.text();
      const data = processCSV(text);

      if (data.length === 0) {
        throw new Error("Não encontramos transações. Certifique-se que a Coluna A é a Data, B é o Valor e C é a Descrição.");
      }

      onImport(data);
    } catch (err: any) {
      alert(`Erro ao importar: ${err.message}`);
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between">
          <h3 className="text-xl font-bold text-slate-800">Importar Dados</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2">
            <i className="fas fa-times text-xl"></i>
          </button>
        </div>

        <div className="p-6">
          <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
            <button 
              onClick={() => setActiveTab('csv')}
