import { GoogleGenAI, Type } from "@google/genai";
import { Transaction, AIInsights } from "../types";

// Initialize the Google GenAI SDK with the API key from environment variables.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeTransactions = async (transactions: Transaction[]): Promise<AIInsights> => {
  const transactionData = transactions.map(t => ({
    date: t.date,
    desc: t.description,
    val: t.amount,
    cat: t.category
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analise o seguinte extrato bancário e forneça insights financeiros. 
    Dados: ${JSON.stringify(transactionData)}

    Por favor, retorne no formato JSON com:
    1. "summary": Um breve resumo do mês financeiro.
    2. "topCategories": Um array de objetos {category, total} com as 3 categorias onde mais se gastou.
    3. "savingTips": Um array com 3 dicas personalizadas para economizar baseadas nos dados.
    4. "anomalies": Um array com possíveis gastos estranhos ou assinaturas esquecidas.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          topCategories: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                category: { type: Type.STRING },
                total: { type: Type.NUMBER }
              },
              required: ["category", "total"]
            }
          },
          savingTips: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          anomalies: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["summary", "topCategories", "savingTips", "anomalies"]
      }
    }
  });

  // Extract text content directly from the response object
  try {
    const text = response.text || '{}';
    return JSON.parse(text) as AIInsights;
  } catch (error) {
    console.error("Erro ao processar insights da AI:", error);
    throw new Error("Falha na análise da AI");
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, AppState, AIInsights, SourceKey, MonthData } from './types';
import { analyzeTransactions } from './services/geminiService';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import SourceManager from './components/SourceManager';
import AIInsightsPanel from './components/AIInsightsPanel';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.EMPTY);
  const [currentMonthId, setCurrentMonthId] = useState(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
  });

  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isSourceManagerOpen, setIsSourceManagerOpen] = useState(false);
  const [insights, setInsights] = useState<AIInsights | null>(null);
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [syncing, setSyncing] = useState(false);

  // Carrega links salvos para o mês atual
  const [monthConfigs, setMonthConfigs] = useState<Record<string, Record<SourceKey, string>>>(() => {
    const saved = localStorage.getItem('ff_month_configs');
    return saved ? JSON.parse(saved) : {};
  });

  useEffect(() => {
    localStorage.setItem('ff_month_configs', JSON.stringify(monthConfigs));
  }, [monthConfigs]);

  const currentSources = useMemo(() => {
    return monthConfigs[currentMonthId] || {
      nubank_pj_pix: '',
      nubank_pf_pix: '',
      nubank_cc: '',
      picpay_pf_pix: '',
      picpay_pj_pix: ''
    } as Record<SourceKey, string>;
  }, [monthConfigs, currentMonthId]);

  const handleUpdateSources = (newSources: Record<SourceKey, string>) => {
    setMonthConfigs(prev => ({
      ...prev,
      [currentMonthId]: newSources
    }));
  };

  const parseValue = (valStr: string): number => {
    if (!valStr) return NaN;
    // Remove R$, espaços e ajusta formatos de milhar/decimal
    let clean = valStr.replace(/[R$\s"]/g, '').trim();

    // Se tiver "+" na string original e for cartão, o parseFloat vai ignorar o +, 
    // mas precisamos garantir que o valor numérico saia correto antes da inversão.
    if (clean.includes(',') && clean.includes('.')) {
      clean = clean.replace(/\./g, '').replace(',', '.');
    } else if (clean.includes(',')) {
      clean = clean.replace(',', '.');
    }

    // O parseFloat lida bem com "+" e "-" no início da string
    return parseFloat(clean);
  };

  const processCSV = (text: string, source: SourceKey): Transaction[] => {
    const lines = text.split(/\r?\n/).filter(l => l.trim().length > 0);
    const result: Transaction[] = [];
    const separator = lines[0].includes(';') ? ';' : ',';

    // Coluna A (0): Data, Coluna B (1): Valor, Coluna C (2): Descrição
    const firstLineParts = lines[0].split(separator);
    const hasHeader = isNaN(parseValue(firstLineParts[1]));
    const startIdx = hasHeader ? 1 : 0;

    for (let i = startIdx; i < lines.length; i++) {
      const parts = lines[i].split(separator).map(p => p.replace(/^"|"$/g, '').trim());
      if (parts.length < 3) continue;

      const dateStr = parts[0];
      let amount = parseValue(parts[1]);
      const desc = parts[2];
      const cat = parts[3] || 'Geral';

      if (isNaN(amount) || !dateStr || !desc) continue;

      // --- Lógica Específica para Nubank CC ---
      if (source === 'nubank_cc') {
        // 1. Desconsiderar "Pagamento recebido" (pagamento da fatura vindo da conta)
        if (desc.toLowerCase().includes('pagamento recebido')) {
          continue;
        }

        // 2. Inverter Sinais (Extrato do cartão vem na perspectiva do banco)
        // Se no extrato está +138.22 (Rede Pratique), para o usuário é um gasto (-138.22)
        amount = amount * -1;
      }

      result.push({
        id: `${source}-${Math.random().toString(36).substr(2, 5)}`,
        date: dateStr,
        description: desc,
        amount: amount,
        category: cat,
        type: amount >= 0 ? 'income' : 'expense',
        source: source
      });
    }
    return result;
  };

  const fetchAllData = async () => {
    setSyncing(true);
    setAppState(AppState.LOADING);
    let allTransactions: Transaction[] = [];

    const activeSources = (Object.entries(currentSources) as [SourceKey, string][]).filter(([_, url]) => url && url.startsWith('http'));

    if (activeSources.length === 0) {
      setTransactions([]);
      setAppState(AppState.EMPTY);
      setSyncing(false);
      return;
    }

    for (const [key, url] of activeSources) {
      try {
        let fetchUrl: string = url;
        if (url.includes('docs.google.com/spreadsheets')) {
          const idMatch = url.match(/\/d\/(.+?)(\/|$)/);
          if (idMatch) fetchUrl = `https://docs.google.com/spreadsheets/d/${idMatch[1]}/export?format=csv`;
        }

        const response = await fetch(fetchUrl);
        if (response.ok) {
          const text = await response.text();
          const sourceTransactions = processCSV(text, key);
          allTransactions = [...allTransactions, ...sourceTransactions];
        }
      } catch (err) {
        console.error(`Erro ao carregar fonte ${key}:`, err);
      }
    }

    setTransactions(allTransactions);
    setAppState(allTransactions.length > 0 ? AppState.READY : AppState.EMPTY);
    setSyncing(false);
    setInsights(null);
  };

  useEffect(() => {
    fetchAllData();
  }, [currentMonthId]);

  const generateAIInsights = async () => {
    if (transactions.length === 0) return;
    setLoadingInsights(true);
    try {
      const result = await analyzeTransactions(transactions);
      setInsights(result);
    } catch (error) {
      alert("Erro na análise. Verifique se a API Key está configurada.");
    } finally {
      setLoadingInsights(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header 
        currentMonthId={currentMonthId}
        onMonthChange={setCurrentMonthId}
        onOpenSources={() => setIsSourceManagerOpen(true)}
        isSyncing={syncing}
        onRefresh={fetchAllData}
      />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        {appState === AppState.EMPTY && !syncing ? (
          <div className="flex flex-col items-center justify-center min-h-[50vh] text-center space-y-6">
            <div className="w-20 h-20 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600 text-3xl">
              <i className="fas fa-plug"></i>
            </div>
            <h2 className="text-2xl font-bold text-slate-800">Nenhuma fonte configurada para este mês</h2>
            <p className="text-slate-500 max-w-sm mx-auto">
              Adicione os links das suas planilhas do Google para o mês de {currentMonthId} para começar.
            </p>
            <button 
              onClick={() => setIsSourceManagerOpen(true)}
              className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-semibold shadow-lg hover:bg-indigo-700 transition-all"
            >
              Configurar Planilhas
            </button>
          </div>
        ) : appState === AppState.LOADING ? (
          <div className="flex flex-col items-center justify-center min-h-[50vh]">
            <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-600 border-t-transparent"></div>
            <p className="mt-4 text-slate-500 font-medium">Sincronizando extratos...</p>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in duration-500">
            <Dashboard transactions={transactions} />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2">
                <TransactionList transactions={transactions} />
              </div>
              <div className="lg:col-span-1">
                <AIInsightsPanel 
                  insights={insights} 
                  isLoading={loadingInsights} 
                  onGenerate={generateAIInsights}
                  hasTransactions={transactions.length > 0}
                />
              </div>
            </div>
          </div>
        )}
      </main>

      {isSourceManagerOpen && (
        <SourceManager 
          onClose={() => setIsSourceManagerOpen(false)} 
          currentSources={currentSources}
          onUpdate={handleUpdateSources}
          onSync={fetchAllData}
          monthLabel={currentMonthId}
        />
      )}
    </div>
  );
};

