    setSyncing(true);
    setAppState(AppState.LOADING);
    let allSpreadsheetTxs: Transaction[] = [];

    const activeSources = (Object.entries(currentSources) as [SourceKey, string][])
      .filter(([key, url]) => key !== 'manual' && url && url.startsWith('http'));

    for (const [key, url] of activeSources) {
      try {
        let fetchUrl: string = url;
        if (url.includes('docs.google.com/spreadsheets')) {
          const idMatch = url.match(/\/d\/(.+?)(\/|$)/);
          if (idMatch) fetchUrl = `https://docs.google.com/spreadsheets/d/${idMatch[1]}/export?format=csv`;
        }

        const response = await fetch(fetchUrl);
        if (response.ok) {
          const text = await response.text();
          const sourceTransactions = processCSV(text, key);
          allSpreadsheetTxs = [...allSpreadsheetTxs, ...sourceTransactions];
        }
      } catch (err) {
        console.error(`Erro ao carregar fonte ${key}:`, err);
      }
    }

    setSpreadsheetTransactions(allSpreadsheetTxs);
    const hasData = allSpreadsheetTxs.length > 0 || (manualTransactions[currentMonthId]?.length || 0) > 0;
    setAppState(hasData ? AppState.READY : AppState.EMPTY);
    setSyncing(false);
    setInsights(null);
  };

  useEffect(() => {
    fetchAllData();
  }, [currentMonthId]);

  const generateAIInsights = async () => {
    if (transactions.length === 0) return;
    setLoadingInsights(true);
    try {
      const result = await analyzeTransactions(transactions);
      setInsights(result);
    } catch (error) {
      alert("Erro na análise. Verifique se a API Key está configurada.");
    } finally {
      setLoadingInsights(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header 
        currentMonthId={currentMonthId}
        onMonthChange={setCurrentMonthId}
        onOpenSources={() => setIsSourceManagerOpen(true)}
        onOpenManual={() => setIsManualModalOpen(true)}
        isSyncing={syncing}
        onRefresh={fetchAllData}
      />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        {appState === AppState.EMPTY && !syncing ? (
          <div className="flex flex-col items-center justify-center min-h-[50vh] text-center space-y-6 animate-in fade-in duration-700">
            <div className="w-20 h-20 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600 text-3xl">
              <i className="fas fa-plug"></i>
            </div>
            <h2 className="text-2xl font-bold text-slate-800">Pronto para começar?</h2>
            <p className="text-slate-500 max-w-sm mx-auto">
              Configure os links das suas planilhas ou adicione um lançamento manual para o mês atual.
            </p>
            <div className="flex gap-3">
              <button 
                onClick={() => setIsSourceManagerOpen(true)}
                className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-semibold shadow-lg hover:bg-indigo-700 transition-all"
              >
                Configurar Planilhas
              </button>
              <button 
                onClick={() => setIsManualModalOpen(true)}
                className="px-6 py-3 bg-white text-indigo-600 border border-indigo-200 rounded-xl font-semibold shadow-sm hover:bg-indigo-50 transition-all"
              >
                Lançamento Manual
              </button>
            </div>
          </div>
        ) : appState === AppState.LOADING ? (
          <div className="flex flex-col items-center justify-center min-h-[50vh]">
            <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-600 border-t-transparent"></div>
            <p className="mt-4 text-slate-500 font-medium">Sincronizando dados...</p>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in duration-500">
            <Dashboard transactions={transactions} />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2">
                <TransactionList transactions={transactions} />
              </div>
              <div className="lg:col-span-1">
                <AIInsightsPanel 
                  insights={insights} 
                  isLoading={loadingInsights} 
                  onGenerate={generateAIInsights}
                  hasTransactions={transactions.length > 0}
                />
              </div>
            </div>
          </div>
        )}
      </main>

      {isSourceManagerOpen && (
        <SourceManager 
          onClose={() => setIsSourceManagerOpen(false)} 
          currentSources={currentSources}
          onUpdate={handleUpdateSources}
          onSync={fetchAllData}
          monthLabel={currentMonthId}
        />
      )}

      {isManualModalOpen && (
        <ManualEntryModal 
          onClose={() => setIsManualModalOpen(false)}
          onAdd={handleAddManualTransaction}
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';

interface HeaderProps {
  currentMonthId: string;
  onMonthChange: (monthId: string) => void;
  onOpenSources: () => void;
  onOpenManual: () => void;
  isSyncing: boolean;
  onRefresh: () => void;
}

const Header: React.FC<HeaderProps> = ({ 
  currentMonthId, 
  onMonthChange, 
  onOpenSources, 
  onOpenManual,
  isSyncing, 
  onRefresh 
}) => {
  const months = [
    'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 
    'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
  ];

  const handlePrevMonth = () => {
    const [year, month] = currentMonthId.split('-').map(Number);
    let newMonth = month - 1;
    let newYear = year;
    if (newMonth === 0) {
      newMonth = 12;
      newYear--;
    }
    onMonthChange(`${newYear}-${String(newMonth).padStart(2, '0')}`);
  };

  const handleNextMonth = () => {
    const [year, month] = currentMonthId.split('-').map(Number);
    let newMonth = month + 1;
    let newYear = year;
    if (newMonth === 13) {
      newMonth = 1;
      newYear++;
    }
    onMonthChange(`${newYear}-${String(newMonth).padStart(2, '0')}`);
  };

  const displayMonth = () => {
    const [year, month] = currentMonthId.split('-').map(Number);
    return `${months[month - 1]} ${year}`;
  };

  return (
    <header className="bg-white border-b border-slate-200 sticky top-0 z-30 shadow-sm">
      <div className="container mx-auto px-4 h-16 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white shadow-indigo-200 shadow-lg">
              <i className="fas fa-wallet"></i>
            </div>
            <h1 className="text-lg font-bold text-slate-900 hidden xs:block tracking-tight">FinanceFlow</h1>
          </div>

          <div className="h-6 w-px bg-slate-200 mx-2 hidden sm:block"></div>

          <div className="flex items-center bg-slate-100 rounded-lg p-1">
            <button onClick={handlePrevMonth} className="p-1.5 hover:bg-white rounded-md transition-all text-slate-500 hover:text-indigo-600">
              <i className="fas fa-chevron-left text-xs"></i>
            </button>
            <span className="px-3 text-sm font-semibold text-slate-700 min-w-[120px] text-center">
              {displayMonth()}
            </span>
            <button onClick={handleNextMonth} className="p-1.5 hover:bg-white rounded-md transition-all text-slate-500 hover:text-indigo-600">
              <i className="fas fa-chevron-right text-xs"></i>
            </button>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={onRefresh}
            disabled={isSyncing}
            className={`p-2 text-slate-500 hover:text-indigo-600 rounded-lg hover:bg-indigo-50 transition-all ${isSyncing ? 'animate-spin' : ''}`}
            title="Sincronizar dados"
          >
            <i className="fas fa-sync-alt"></i>
          </button>

          <button 
            onClick={onOpenManual}
            className="hidden sm:flex items-center gap-2 bg-indigo-50 text-indigo-600 hover:bg-indigo-100 px-4 py-2 rounded-lg text-sm font-bold transition-all border border-indigo-100"
          >
            <i className="fas fa-plus"></i>
            Novo Lançamento
          </button>

          <button 
            onClick={onOpenSources}
            className="flex items-center gap-2 bg-slate-900 hover:bg-slate-800 text-white px-4 py-2 rounded-lg text-sm font-medium transition-all shadow-md shadow-slate-200"
          >
            <i className="fas fa-cog"></i>
            <span className="hidden md:inline">Configurar Fontes</span>
          </button>

          <button 
            onClick={onOpenManual}
            className="sm:hidden w-10 h-10 flex items-center justify-center bg-indigo-600 text-white rounded-full shadow-lg"
          >
            <i className="fas fa-plus"></i>
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useState } from 'react';
import { Transaction, SourceKey } from '../types';

interface ManualEntryModalProps {
  onClose: () => void;
  onAdd: (tx: Transaction) => void;
}

const ManualEntryModal: React.FC<ManualEntryModalProps> = ({ onClose, onAdd }) => {
  const [date, setDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [sourceLabel, setSourceLabel] = useState('Dinheiro');
  const [type, setType] = useState<'income' | 'expense'>('expense');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    const numAmount = Math.abs(parseFloat(amount));
    const finalAmount = type === 'expense' ? -numAmount : numAmount;

    const newTx: Transaction = {
      id: `manual-${Date.now()}`,
      date: date.split('-').reverse().join('/'), // Converte para DD/MM/AAAA para manter padrão das planilhas
      description: description,
      amount: finalAmount,
      category: 'Manual',
      type: type,
      source: 'manual',
      manualSourceLabel: sourceLabel
    };

    onAdd(newTx);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
        <form onSubmit={handleSubmit}>
          <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
            <div>
              <h3 className="text-xl font-bold text-slate-800">Novo Lançamento</h3>
              <p className="text-sm text-slate-500">Adicione um gasto ou ganho manual</p>
            </div>
            <button type="button" onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2">
              <i className="fas fa-times text-xl"></i>
            </button>
          </div>

          <div className="p-6 space-y-4">
            <div className="flex bg-slate-100 p-1 rounded-xl mb-2">
              <button 
                type="button"
                onClick={() => setType('expense')}
                className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${type === 'expense' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-500'}`}
              >
                Saída
              </button>
              <button 
                type="button"
                onClick={() => setType('income')}
                className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${type === 'income' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500'}`}
              >
                Entrada
              </button>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Data</label>
                <input 
                  type="date" 
                  required
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500/20 focus:outline-none"
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Fonte</label>
                <select 
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500/20 focus:outline-none"
                  value={sourceLabel}
                  onChange={(e) => setSourceLabel(e.target.value)}
                >
                  <option>Dinheiro</option>
                  <option>Pix Manual</option>
                  <option>Transferência</option>
                  <option>Outros</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Descrição</label>
              <input 
                type="text" 
                placeholder="Ex: Almoço no quilo, Pagamento João..."
                required
                className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500/20 focus:outline-none"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Valor (R$)</label>
              <input 
                type="number" 
                step="0.01"
                placeholder="0,00"
                required
                className={`w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-lg font-bold focus:outline-none focus:ring-2 focus:ring-indigo-500/20 ${type === 'expense' ? 'text-rose-600' : 'text-emerald-600'}`}
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
              />
            </div>
          </div>

          <div className="p-6 border-t border-slate-100">
            <button 
              type="submit"
              className={`w-full py-4 text-white font-bold rounded-2xl shadow-lg transition-all transform hover:scale-[1.02] active:scale-[0.98] ${type === 'expense' ? 'bg-rose-500 hover:bg-rose-600' : 'bg-emerald-500 hover:bg-emerald-600'}`}
            >
              Salvar Lançamento
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

