import React, { useMemo } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Transaction, SourceKey } from '../types';

interface DashboardProps {
  transactions: Transaction[];
}

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#f97316'];

const SOURCE_LABELS: Record<SourceKey, string> = {
  nubank_pj_pix: 'Nubank PJ',
  nubank_pf_pix: 'Nubank PF',
  nubank_cc: 'Nubank Cartão',
  picpay_pf_pix: 'PicPay PF',
  picpay_pj_pix: 'PicPay PJ',
  manual: 'Manual'
};

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const income = transactions.filter(t => t.type === 'income').reduce((sum, t) => sum + t.amount, 0);
    const expenses = transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + Math.abs(t.amount), 0);
    const balance = income - expenses;

    // Distribuição por Fonte (Source)
    const sourceMap: Record<string, number> = {};
    transactions.filter(t => t.type === 'expense').forEach(t => {
      const label = t.source === 'manual' && t.manualSourceLabel ? t.manualSourceLabel : (SOURCE_LABELS[t.source] || 'Outros');
      sourceMap[label] = (sourceMap[label] || 0) + Math.abs(t.amount);
    });

    const sourceData = Object.entries(sourceMap).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);

    // Group by category
    const categoryMap: Record<string, number> = {};
    transactions.filter(t => t.type === 'expense').forEach(t => {
      categoryMap[t.category] = (categoryMap[t.category] || 0) + Math.abs(t.amount);
    });
    const pieData = Object.entries(categoryMap).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);

    return { income, expenses, balance, sourceData, pieData };
  }, [transactions]);

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm transition-all hover:shadow-md">
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Entradas Consolidadas</p>
          <p className="text-2xl font-black text-emerald-600 mt-1">{formatCurrency(stats.income)}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm transition-all hover:shadow-md">
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Saídas Consolidadas</p>
          <p className="text-2xl font-black text-rose-600 mt-1">{formatCurrency(stats.expenses)}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm transition-all hover:shadow-md">
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Saldo do Mês</p>
          <p className={`text-2xl font-black mt-1 ${stats.balance >= 0 ? 'text-indigo-600' : 'text-red-600'}`}>
            {formatCurrency(stats.balance)}
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider flex items-center gap-2">
            <i className="fas fa-chart-pie text-indigo-500"></i>
            Gastos por Fonte
          </h3>
          <div className="h-[250px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={stats.sourceData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                  {stats.sourceData.map((_, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => formatCurrency(value)} />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 grid grid-cols-2 gap-x-4 gap-y-2">
            {stats.sourceData.map((entry, idx) => (
              <div key={idx} className="flex items-center justify-between text-[11px] text-slate-600">
                <div className="flex items-center gap-2 truncate">
                  <div className="w-2 h-2 rounded-full flex-shrink-0" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></div>
                  <span className="truncate">{entry.name}</span>
                </div>
                <span className="font-bold text-slate-800 ml-1">{Math.round((entry.value / stats.expenses) * 100)}%</span>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider flex items-center gap-2">
            <i className="fas fa-list-ul text-indigo-500"></i>
            Principais Categorias
          </h3>
          <div className="space-y-4">
            {stats.pieData.length > 0 ? stats.pieData.slice(0, 5).map((item, idx) => (
              <div key={idx} className="space-y-1">
                <div className="flex justify-between text-xs font-medium">
                  <span className="text-slate-700">{item.name}</span>
                  <span className="text-slate-900 font-bold">{formatCurrency(item.value)}</span>
                </div>
                <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-indigo-500 rounded-full" 
                    style={{ width: `${(item.value / stats.expenses) * 100}%` }}
                  ></div>
                </div>
              </div>
            )) : (
              <p className="text-center py-12 text-slate-400 text-sm italic">Sem gastos registrados</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, AppState, SourceKey } from './types';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import SourceManager from './components/SourceManager';
import ManualEntryModal from './components/ManualEntryModal';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.EMPTY);
  const [currentMonthId, setCurrentMonthId] = useState(() => {
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
  });

  const [spreadsheetTransactions, setSpreadsheetTransactions] = useState<Transaction[]>([]);
  const [manualTransactions, setManualTransactions] = useState<Record<string, Transaction[]>>(() => {
    const saved = localStorage.getItem('ff_manual_txs');
    return saved ? JSON.parse(saved) : {};
  });

  const [ignoredIds, setIgnoredIds] = useState<string[]>(() => {
    const saved = localStorage.getItem('ff_ignored_ids');
    return saved ? JSON.parse(saved) : [];
  });

  const [isSourceManagerOpen, setIsSourceManagerOpen] = useState(false);
  const [isManualModalOpen, setIsManualModalOpen] = useState(false);
  const [syncing, setSyncing] = useState(false);

  // Links das planilhas
  const [monthConfigs, setMonthConfigs] = useState<Record<string, Record<SourceKey, string>>>(() => {
    const saved = localStorage.getItem('ff_month_configs');
    return saved ? JSON.parse(saved) : {};
  });

  // Persistência
  useEffect(() => {
    localStorage.setItem('ff_month_configs', JSON.stringify(monthConfigs));
  }, [monthConfigs]);

  useEffect(() => {
    localStorage.setItem('ff_manual_txs', JSON.stringify(manualTransactions));
  }, [manualTransactions]);

  useEffect(() => {
    localStorage.setItem('ff_ignored_ids', JSON.stringify(ignoredIds));
  }, [ignoredIds]);

  const currentSources = useMemo(() => {
    return monthConfigs[currentMonthId] || {
      nubank_pj_pix: '',
      nubank_pf_pix: '',
      nubank_cc: '',
      picpay_pf_pix: '',
      picpay_pj_pix: '',
      manual: ''
    } as Record<SourceKey, string>;
  }, [monthConfigs, currentMonthId]);

  // Todas as transações do mês (incluindo ignoradas para a lista)
  const allTransactions = useMemo(() => {
    const manuals = manualTransactions[currentMonthId] || [];
    return [...spreadsheetTransactions, ...manuals].sort((a, b) => {
      const parseDate = (d: string) => {
        const [day, month, year] = d.split('/');
        return new Date(`${year}-${month}-${day}`).getTime();
      };
      return parseDate(b.date) - parseDate(a.date);
    });
  }, [spreadsheetTransactions, manualTransactions, currentMonthId]);

  // Transações ativas para o Dashboard (não ignoradas)
  const activeTransactions = useMemo(() => {
    return allTransactions.filter(t => !ignoredIds.includes(t.id));
  }, [allTransactions, ignoredIds]);

  const handleToggleIgnore = (id: string) => {
    setIgnoredIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const handleUpdateSources = (newSources: Record<SourceKey, string>) => {
    setMonthConfigs(prev => ({
      ...prev,
      [currentMonthId]: newSources
    }));
  };

  const handleAddManualTransaction = (tx: Transaction) => {
    setManualTransactions(prev => {
      const monthTxs = prev[currentMonthId] || [];
      return {
        ...prev,
        [currentMonthId]: [...monthTxs, tx]
      };
    });
    setAppState(AppState.READY);
  };

  const parseValue = (valStr: string): number => {
    if (!valStr) return NaN;
    let clean = valStr.replace(/[R$\s"]/g, '').trim();
    if (clean.includes(',') && clean.includes('.')) {
      clean = clean.replace(/\./g, '').replace(',', '.');
    } else if (clean.includes(',')) {
      clean = clean.replace(',', '.');
    }
    return parseFloat(clean);
  };

  const processCSV = (text: string, source: SourceKey): Transaction[] => {
    const lines = text.split(/\r?\n/).filter(l => l.trim().length > 0);
    const result: Transaction[] = [];
    const separator = lines[0].includes(';') ? ';' : ',';

    const firstLineParts = lines[0].split(separator);
    const hasHeader = isNaN(parseValue(firstLineParts[1]));
    const startIdx = hasHeader ? 1 : 0;

    for (let i = startIdx; i < lines.length; i++) {
      const parts = lines[i].split(separator).map(p => p.replace(/^"|"$/g, '').trim());
      if (parts.length < 3) continue;

      const dateStr = parts[0];
      let amount = parseValue(parts[1]);
      const desc = parts[2];
      const cat = parts[3] || 'Geral';

      if (isNaN(amount) || !dateStr || !desc) continue;

      if (source === 'nubank_cc') {
        if (desc.toLowerCase().includes('pagamento recebido')) continue;
        amount = amount * -1;
      }

      result.push({
        id: `${source}-${Math.random().toString(36).substr(2, 5)}-${i}`,
        date: dateStr,
        description: desc,
        amount: amount,
        category: cat,
        type: amount >= 0 ? 'income' : 'expense',
        source: source
      });
    }
    return result;
  };

  const fetchAllData = async () => {
    setSyncing(true);
    setAppState(AppState.LOADING);
    let allSpreadsheetTxs: Transaction[] = [];

    const activeSources = (Object.entries(currentSources) as [SourceKey, string][])
      .filter(([key, url]) => key !== 'manual' && url && url.startsWith('http'));

    for (const [key, url] of activeSources) {
      try {
        let fetchUrl: string = url;
        if (url.includes('docs.google.com/spreadsheets')) {
          const idMatch = url.match(/\/d\/(.+?)(\/|$)/);
          if (idMatch) fetchUrl = `https://docs.google.com/spreadsheets/d/${idMatch[1]}/export?format=csv`;
        }

        const response = await fetch(fetchUrl);
        if (response.ok) {
          const text = await response.text();
          const sourceTransactions = processCSV(text, key);
          allSpreadsheetTxs = [...allSpreadsheetTxs, ...sourceTransactions];
        }
      } catch (err) {
        console.error(`Erro ao carregar fonte ${key}:`, err);
      }
    }

    setSpreadsheetTransactions(allSpreadsheetTxs);
    const hasData = allSpreadsheetTxs.length > 0 || (manualTransactions[currentMonthId]?.length || 0) > 0;
    setAppState(hasData ? AppState.READY : AppState.EMPTY);
    setSyncing(false);
  };

  useEffect(() => {
    fetchAllData();
  }, [currentMonthId]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header 
        currentMonthId={currentMonthId}
        onMonthChange={setCurrentMonthId}
        onOpenSources={() => setIsSourceManagerOpen(true)}
        onOpenManual={() => setIsManualModalOpen(true)}
        isSyncing={syncing}
        onRefresh={fetchAllData}
      />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-6xl">
        {appState === AppState.EMPTY && !syncing ? (
          <div className="flex flex-col items-center justify-center min-h-[50vh] text-center space-y-6 animate-in fade-in duration-700">
            <div className="w-20 h-20 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600 text-3xl">
              <i className="fas fa-plug"></i>
            </div>
            <h2 className="text-2xl font-bold text-slate-800">Pronto para começar?</h2>
            <p className="text-slate-500 max-w-sm mx-auto">
              Configure os links das suas planilhas ou adicione um lançamento manual para o mês atual.
            </p>
            <div className="flex gap-3">
              <button 
                onClick={() => setIsSourceManagerOpen(true)}
                className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-semibold shadow-lg hover:bg-indigo-700 transition-all"
              >
                Configurar Planilhas
              </button>
              <button 
                onClick={() => setIsManualModalOpen(true)}
                className="px-6 py-3 bg-white text-indigo-600 border border-indigo-200 rounded-xl font-semibold shadow-sm hover:bg-indigo-50 transition-all"
              >
                Lançamento Manual
              </button>
            </div>
          </div>
        ) : appState === AppState.LOADING ? (
          <div className="flex flex-col items-center justify-center min-h-[50vh]">
            <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-600 border-t-transparent"></div>
            <p className="mt-4 text-slate-500 font-medium">Sincronizando dados...</p>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in duration-500">
            <Dashboard transactions={activeTransactions} />
            <TransactionList 
              transactions={allTransactions} 
              ignoredIds={ignoredIds}
              onToggleIgnore={handleToggleIgnore}
            />
          </div>
        )}
      </main>

      {isSourceManagerOpen && (
        <SourceManager 
          onClose={() => setIsSourceManagerOpen(false)} 
          currentSources={currentSources}
          onUpdate={handleUpdateSources}
          onSync={fetchAllData}
          monthLabel={currentMonthId}
        />
      )}

      {isManualModalOpen && (
        <ManualEntryModal 
          onClose={() => setIsManualModalOpen(false)}
          onAdd={handleAddManualTransaction}
        />
      )}
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Transaction, SourceKey } from '../types';

interface DashboardProps {
  transactions: Transaction[];
}

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#f97316'];

const SOURCE_LABELS: Record<SourceKey, string> = {
  nubank_pj_pix: 'Nubank PJ',
  nubank_pf_pix: 'Nubank PF',
  nubank_cc: 'Nubank Cartão',
  picpay_pf_pix: 'PicPay PF',
  picpay_pj_pix: 'PicPay PJ',
  manual: 'Manual'
};

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const isPix = (t: Transaction) => 
      t.source !== 'nubank_cc' && 
      (t.source.includes('pix') || (t.source === 'manual' && t.manualSourceLabel?.toLowerCase().includes('pix')));

    const isCredit = (t: Transaction) => t.source === 'nubank_cc';

    const income = transactions.filter(t => t.type === 'income');
    const incomeTotal = income.reduce((sum, t) => sum + t.amount, 0);
    const incomePix = income.filter(isPix).reduce((sum, t) => sum + t.amount, 0);
    const incomeCredit = income.filter(isCredit).reduce((sum, t) => sum + t.amount, 0);

    const expenses = transactions.filter(t => t.type === 'expense');
    const expensesTotal = expenses.reduce((sum, t) => sum + Math.abs(t.amount), 0);
    const expensesPix = expenses.filter(isPix).reduce((sum, t) => sum + Math.abs(t.amount), 0);
    const expensesCredit = expenses.filter(isCredit).reduce((sum, t) => sum + Math.abs(t.amount), 0);

    const balance = incomeTotal - expensesTotal;
    const balancePix = incomePix - expensesPix;
    const balanceCredit = incomeCredit - expensesCredit;

    // Gastos por Fonte
    const sourceMap: Record<string, number> = {};
    expenses.forEach(t => {
      const label = t.source === 'manual' && t.manualSourceLabel ? t.manualSourceLabel : (SOURCE_LABELS[t.source] || 'Outros');
      sourceMap[label] = (sourceMap[label] || 0) + Math.abs(t.amount);
    });

    const sourceData = Object.entries(sourceMap).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);

    // Gastos por Categoria
    const categoryMap: Record<string, number> = {};
    expenses.forEach(t => {
      categoryMap[t.category] = (categoryMap[t.category] || 0) + Math.abs(t.amount);
    });
    const pieData = Object.entries(categoryMap).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);

    return { 
      incomeTotal, incomePix, incomeCredit,
      expensesTotal, expensesPix, expensesCredit,
      balance, balancePix, balanceCredit,
      sourceData, pieData 
    };
  }, [transactions]);

  const formatCurrency = (val: number) => {
    const isNegative = val < 0;
    const formatted = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Math.abs(val));
    return isNegative ? `-${formatted}` : formatted;
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {/* Entradas Card */}
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Entradas Consolidadas</p>
          <p className="text-2xl font-black text-emerald-600 mt-1">{formatCurrency(stats.incomeTotal)}</p>
          <div className="mt-3 flex gap-3 border-t border-slate-50 pt-3">
            <div className="text-[10px]">
              <span className="text-slate-400 uppercase font-bold mr-1">Pix:</span>
              <span className="text-emerald-600 font-bold">{formatCurrency(stats.incomePix)}</span>
            </div>
            <div className="text-[10px]">
              <span className="text-slate-400 uppercase font-bold mr-1">Crédito:</span>
              <span className="text-emerald-600 font-bold">{formatCurrency(stats.incomeCredit)}</span>
            </div>
          </div>
        </div>

        {/* Saídas Card */}
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Saídas Consolidadas</p>
          <p className="text-2xl font-black text-rose-600 mt-1">{formatCurrency(stats.expensesTotal)}</p>
          <div className="mt-3 flex gap-3 border-t border-slate-50 pt-3">
            <div className="text-[10px]">
              <span className="text-slate-400 uppercase font-bold mr-1">Pix:</span>
              <span className="text-rose-600 font-bold">{formatCurrency(stats.expensesPix)}</span>
            </div>
            <div className="text-[10px]">
              <span className="text-slate-400 uppercase font-bold mr-1">Crédito:</span>
              <span className="text-rose-600 font-bold">{formatCurrency(stats.expensesCredit)}</span>
            </div>
          </div>
        </div>

        {/* Saldo Card */}
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">Saldo do Mês</p>
          <p className={`text-2xl font-black mt-1 ${stats.balance >= 0 ? 'text-indigo-600' : 'text-rose-700'}`}>
            {formatCurrency(stats.balance)}
          </p>
          <div className="mt-3 flex gap-3 border-t border-slate-50 pt-3">
            <div className="text-[10px]">
              <span className="text-slate-400 uppercase font-bold mr-1">Pix:</span>
              <span className={`${stats.balancePix >= 0 ? 'text-indigo-600' : 'text-rose-600'} font-bold`}>{formatCurrency(stats.balancePix)}</span>
            </div>
            <div className="text-[10px]">
              <span className="text-slate-400 uppercase font-bold mr-1">Crédito:</span>
              <span className={`${stats.balanceCredit >= 0 ? 'text-indigo-600' : 'text-rose-600'} font-bold`}>{formatCurrency(stats.balanceCredit)}</span>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider flex items-center gap-2">
            <i className="fas fa-chart-pie text-indigo-500"></i>
            Gastos por Fonte
          </h3>
          <div className="h-[250px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={stats.sourceData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                  {stats.sourceData.map((_, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => formatCurrency(value)} />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 grid grid-cols-2 gap-x-4 gap-y-2">
            {stats.sourceData.map((entry, idx) => (
              <div key={idx} className="flex items-center justify-between text-[11px] text-slate-600">
                <div className="flex items-center gap-2 truncate">
                  <div className="w-2 h-2 rounded-full flex-shrink-0" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></div>
                  <span className="truncate">{entry.name}</span>
                </div>
                <span className="font-bold text-slate-800 ml-1">
                  {stats.expensesTotal > 0 ? Math.round((entry.value / stats.expensesTotal) * 100) : 0}%
                </span>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="text-sm font-bold text-slate-800 mb-6 uppercase tracking-wider flex items-center gap-2">
            <i className="fas fa-list-ul text-indigo-500"></i>
            Principais Categorias
          </h3>
          <div className="space-y-4">
            {stats.pieData.length > 0 ? stats.pieData.slice(0, 5).map((item, idx) => (
              <div key={idx} className="space-y-1">
                <div className="flex justify-between text-xs font-medium">
                  <span className="text-slate-700">{item.name}</span>
                  <span className="text-slate-900 font-bold">{formatCurrency(item.value)}</span>
                </div>
                <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-indigo-500 rounded-full" 
                    style={{ width: `${stats.expensesTotal > 0 ? (item.value / stats.expensesTotal) * 100 : 0}%` }}
                  ></div>
                </div>
              </div>
            )) : (
              <p className="text-center py-12 text-slate-400 text-sm italic">Sem gastos registrados</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Transaction, SourceKey } from '../types';

interface TransactionListProps {
  transactions: Transaction[];
  ignoredIds: string[];
  onToggleIgnore: (id: string) => void;
}

const SOURCE_LABELS: Record<SourceKey, string> = {
  nubank_pj_pix: 'Nubank PJ',
  nubank_pf_pix: 'Nubank PF',
  nubank_cc: 'Nubank CC',
  picpay_pf_pix: 'PicPay PF',
  picpay_pj_pix: 'PicPay PJ',
  manual: 'Manual'
};

const TransactionList: React.FC<TransactionListProps> = ({ transactions, ignoredIds, onToggleIgnore }) => {
  const [filter, setFilter] = useState('');
  const [openMenuId, setOpenMenuId] = useState<string | null>(null);

  const filtered = transactions.filter(t => 
    t.description.toLowerCase().includes(filter.toLowerCase()) ||
    t.category.toLowerCase().includes(filter.toLowerCase())
  );

  const formatCurrency = (val: number) => {
    const isNegative = val < 0;
    const formatted = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Math.abs(val));
    return isNegative ? `-${formatted}` : formatted;
  };

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full relative">
      <div className="p-6 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <h3 className="text-lg font-bold text-slate-800">Histórico Consolidado</h3>
        <div className="relative">
          <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm"></i>
          <input 
            type="text" 
            placeholder="Filtrar por descrição..."
            className="pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 w-full sm:w-64"
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto overflow-y-visible">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-slate-500">
            <tr>
              <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-widest">Data</th>
              <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-widest">Fonte</th>
              <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-widest">Descrição</th>
              <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-widest text-right">Valor</th>
              <th className="px-6 py-4 w-10"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filtered.length > 0 ? filtered.map((t) => {
              const isIgnored = ignoredIds.includes(t.id);
              return (
                <tr 
                  key={t.id} 
                  className={`transition-colors relative group ${isIgnored ? 'bg-slate-50 text-slate-400 opacity-60 italic line-through' : 'hover:bg-slate-50/50'}`}
                >
                  <td className="px-6 py-4 whitespace-nowrap">
                    {t.date}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-md ${
                      isIgnored 
                        ? 'bg-slate-200 text-slate-500' 
                        : t.source === 'manual' 
                          ? 'bg-amber-100 text-amber-700' 
                          : t.source.includes('nubank') 
                            ? 'bg-purple-100 text-purple-700' 
                            : 'bg-emerald-100 text-emerald-700'
                    }`}>
                      {t.source === 'manual' ? t.manualSourceLabel : SOURCE_LABELS[t.source]}
                    </span>
                  </td>
                  <td className="px-6 py-4 font-medium max-w-xs truncate">
                    {t.description}
                  </td>
                  <td className={`px-6 py-4 text-right font-bold ${isIgnored ? 'text-slate-400' : t.type === 'income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                    {t.type === 'income' && !isIgnored ? '+' : ''} {formatCurrency(t.amount)}
                  </td>
                  <td className="px-6 py-4 text-right relative">
                    <button 
                      onClick={() => setOpenMenuId(openMenuId === t.id ? null : t.id)}
                      className="p-1 hover:bg-slate-200 rounded-lg text-slate-400 transition-all"
                    >
                      <i className="fas fa-ellipsis-v"></i>
                    </button>
                    {openMenuId === t.id && (
                      <>
                        <div 
                          className="fixed inset-0 z-10" 
                          onClick={() => setOpenMenuId(null)}
                        ></div>
                        <div className="absolute right-6 top-10 bg-white border border-slate-200 rounded-xl shadow-xl py-2 w-48 z-20 animate-in fade-in zoom-in-95 duration-100">
                          <button 
                            onClick={() => {
                              onToggleIgnore(t.id);
                              setOpenMenuId(null);
                            }}
                            className="w-full px-4 py-2 text-left text-xs font-bold hover:bg-slate-50 flex items-center gap-2 transition-colors"
                          >
                            <i className={isIgnored ? "fas fa-check-circle text-emerald-500" : "fas fa-eye-slash text-slate-500"}></i>
                            {isIgnored ? 'Reconsiderar' : 'Desconsiderar'}
                          </button>
                        </div>
                      </>
                    )}
                  </td>
                </tr>
              );
            }) : (
              <tr>
                <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                  Nenhuma transação encontrada para este mês.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TransactionList;

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, AppState, SourceKey } from './types';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import TransactionList from './components/TransactionList';
import SourceManager from './components/SourceManager';
import ManualEntryModal from './components/ManualEntryModal';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.EMPTY);
  const [selectedMonths, setSelectedMonths] = useState<string[]>(() => {
    const d = new Date();
    return [`${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`];
  });

  const [spreadsheetTransactions, setSpreadsheetTransactions] = useState<Record<string, Transaction[]>>({});
  const [manualTransactions, setManualTransactions] = useState<Record<string, Transaction[]>>(() => {
    const saved = localStorage.getItem('ff_manual_txs');
    return saved ? JSON.parse(saved) : {};
  });

  const [ignoredIds, setIgnoredIds] = useState<string[]>(() => {
    const saved = localStorage.getItem('ff_ignored_ids');
    return saved ? JSON.parse(saved) : [];
  });

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isSourceManagerOpen, setIsSourceManagerOpen] = useState(false);
  const [isManualModalOpen, setIsManualModalOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [syncing, setSyncing] = useState(false);

  const [monthConfigs, setMonthConfigs] = useState<Record<string, Record<SourceKey, string>>>(() => {
    const saved = localStorage.getItem('ff_month_configs');
    return saved ? JSON.parse(saved) : {};
  });

  useEffect(() => {
    localStorage.setItem('ff_month_configs', JSON.stringify(monthConfigs));
  }, [monthConfigs]);

  useEffect(() => {
    localStorage.setItem('ff_manual_txs', JSON.stringify(manualTransactions));
  }, [manualTransactions]);

  useEffect(() => {
    localStorage.setItem('ff_ignored_ids', JSON.stringify(ignoredIds));
  }, [ignoredIds]);

  const allSelectedTransactions = useMemo(() => {
    let combined: Transaction[] = [];
    selectedMonths.forEach(mId => {
      const sheetTxs = spreadsheetTransactions[mId] || [];
      const manuals = manualTransactions[mId] || [];
      combined = [...combined, ...sheetTxs, ...manuals];
    });

    return combined.sort((a, b) => {
      const parseDate = (d: string) => {
        const [day, month, year] = d.split('/');
        return new Date(`${year}-${month}-${day}`).getTime();
      };
      return parseDate(b.date) - parseDate(a.date);
    });
  }, [spreadsheetTransactions, manualTransactions, selectedMonths]);

  const activeTransactions = useMemo(() => {
    return allSelectedTransactions.filter(t => !ignoredIds.includes(t.id));
  }, [allSelectedTransactions, ignoredIds]);

  const handleToggleIgnore = (id: string) => {
    setIgnoredIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const handleUpdateSources = (newSources: Record<SourceKey, string>) => {
    // Atualiza apenas para o primeiro mês selecionado ou uma lógica global? 
    // Vamos atualizar para o mês ativo (o primeiro da lista de seleção)
    const activeM = selectedMonths[0];
    setMonthConfigs(prev => ({ ...prev, [activeM]: newSources }));
  };

  const handleAddOrEditManual = (tx: Transaction) => {
    // Pega o mês da transação (DD/MM/AAAA -> YYYY-MM)
    const [d, m, y] = tx.date.split('/');
    const mId = `${y}-${m}`;

    setManualTransactions(prev => {
      const monthTxs = prev[mId] || [];
      const exists = monthTxs.find(t => t.id === tx.id);
      if (exists) {
        return {
          ...prev,
          [mId]: monthTxs.map(t => t.id === tx.id ? tx : t)
        };
      }
      return {
        ...prev,
        [mId]: [...monthTxs, tx]
      };
    });
    setAppState(AppState.READY);
    setEditingTransaction(null);
  };

  const parseValue = (valStr: string): number => {
    if (!valStr) return NaN;
    let clean = valStr.replace(/[R$\s"]/g, '').trim();
    if (clean.includes(',') && clean.includes('.')) {
      clean = clean.replace(/\./g, '').replace(',', '.');
    } else if (clean.includes(',')) {
      clean = clean.replace(',', '.');
    }
    return parseFloat(clean);
  };

  const processCSV = (text: string, source: SourceKey): Transaction[] => {
    const lines = text.split(/\r?\n/).filter(l => l.trim().length > 0);
    const result: Transaction[] = [];
    const separator = lines[0].includes(';') ? ';' : ',';
    const hasHeader = isNaN(parseValue(lines[0].split(separator)[1]));
    const startIdx = hasHeader ? 1 : 0;

    for (let i = startIdx; i < lines.length; i++) {
      const parts = lines[i].split(separator).map(p => p.replace(/^"|"$/g, '').trim());
      if (parts.length < 3) continue;
      const dateStr = parts[0];
      let amount = parseValue(parts[1]);
      const desc = parts[2];
      const cat = parts[3] || 'Geral';
      if (isNaN(amount) || !dateStr || !desc) continue;
      if (source === 'nubank_cc') {
        if (desc.toLowerCase().includes('pagamento recebido')) continue;
        amount = amount * -1;
      }
      result.push({
        id: `${source}-${dateStr}-${desc}-${amount}-${i}`,
        date: dateStr,
        description: desc,
        amount: amount,
        category: cat,
        type: amount >= 0 ? 'income' : 'expense',
        source: source
      });
    }
    return result;
  };

  const fetchAllData = async () => {
    setSyncing(true);
    setAppState(AppState.LOADING);
    const newSpreadsheetData: Record<string, Transaction[]> = { ...spreadsheetTransactions };

    for (const mId of selectedMonths) {
      const sources = monthConfigs[mId] || {};
      const activeSources = (Object.entries(sources) as [SourceKey, string][])
        .filter(([key, url]) => key !== 'manual' && url && url.startsWith('http'));

      let monthTxs: Transaction[] = [];
      for (const [key, url] of activeSources) {
        try {
          let fetchUrl = url;
          if (url.includes('docs.google.com/spreadsheets')) {
            const idMatch = url.match(/\/d\/(.+?)(\/|$)/);
            if (idMatch) fetchUrl = `https://docs.google.com/spreadsheets/d/${idMatch[1]}/export?format=csv`;
          }
          const response = await fetch(fetchUrl);
          if (response.ok) {
            const text = await response.text();
            monthTxs = [...monthTxs, ...processCSV(text, key)];
          }
        } catch (err) { console.error(err); }
      }
      newSpreadsheetData[mId] = monthTxs;
    }

    setSpreadsheetTransactions(newSpreadsheetData);
    setAppState(AppState.READY);
    setSyncing(false);
  };

  useEffect(() => {
    fetchAllData();
  }, [selectedMonths]);

  return (
    <div className="min-h-screen bg-slate-50 flex">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        selectedMonths={selectedMonths}
        onMonthToggle={(mId) => {
          setSelectedMonths(prev => prev.includes(mId) ? prev.filter(m => m !== mId) : [...prev, mId]);
        }}
        onSelectAll={(months) => setSelectedMonths(months)}
      />

      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'ml-0 md:ml-64' : 'ml-0'}`}>
        <Header 
          currentMonthId={selectedMonths[0] || ""}
          onMonthChange={(m) => setSelectedMonths([m])}
          onOpenSources={() => setIsSourceManagerOpen(true)}
          onOpenManual={() => setIsManualModalOpen(true)}
          onToggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
          isSyncing={syncing}
          onRefresh={fetchAllData}
        />

        <main className="flex-grow container mx-auto px-4 py-8 max-w-6xl">
          {activeTransactions.length === 0 && !syncing ? (
            <div className="flex flex-col items-center justify-center min-h-[50vh] text-center space-y-6">
              <div className="w-20 h-20 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600 text-3xl">
                <i className="fas fa-folder-open"></i>
              </div>
              <h2 className="text-2xl font-bold text-slate-800">Nada por aqui ainda</h2>
              <p className="text-slate-500 max-w-sm mx-auto">
                Selecione um mês na barra lateral ou configure uma fonte de dados.
              </p>
            </div>
          ) : syncing ? (
            <div className="flex flex-col items-center justify-center min-h-[50vh]">
              <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-600 border-t-transparent"></div>
              <p className="mt-4 text-slate-500 font-medium">Consolidando informações...</p>
            </div>
          ) : (
            <div className="space-y-8 animate-in fade-in duration-500">
              <Dashboard transactions={activeTransactions} />
              <TransactionList 
                transactions={allSelectedTransactions} 
                ignoredIds={ignoredIds}
                onToggleIgnore={handleToggleIgnore}
                onEdit={(tx) => {
                  setEditingTransaction(tx);
                  setIsManualModalOpen(true);
                }}
              />
            </div>
          )}
        </main>
      </div>

      {isSourceManagerOpen && (
        <SourceManager 
          onClose={() => setIsSourceManagerOpen(false)} 
          currentSources={monthConfigs[selectedMonths[0]] || { manual: '' } as any}
          onUpdate={handleUpdateSources}
          onSync={fetchAllData}
          monthLabel={selectedMonths.join(', ')}
        />
      )}

      {isManualModalOpen && (
        <ManualEntryModal 
          onClose={() => {
            setIsManualModalOpen(false);
            setEditingTransaction(null);
          }}
          onAdd={handleAddOrEditManual}
          editTransaction={editingTransaction}
        />
      )}
    </div>
  );
};

export default App;

