import React, { useState } from 'react';
import { Transaction, SourceKey } from '../types';

interface TransactionListProps {
  transactions: Transaction[];
  ignoredIds: string[];
  onToggleIgnore: (id: string) => void;
  onEdit: (tx: Transaction) => void;
}

const SOURCE_LABELS: Record<SourceKey, string> = {
  nubank_pj_pix: 'Nubank PJ',
  nubank_pf_pix: 'Nubank PF',
  nubank_cc: 'Nubank CC',
  picpay_pf_pix: 'PicPay PF',
  picpay_pj_pix: 'PicPay PJ',
  manual: 'Manual'
};

const TransactionList: React.FC<TransactionListProps> = ({ transactions, ignoredIds, onToggleIgnore, onEdit }) => {
  const [filter, setFilter] = useState('');
  const [openMenuId, setOpenMenuId] = useState<string | null>(null);

  const filtered = transactions.filter(t => 
    t.description.toLowerCase().includes(filter.toLowerCase()) ||
    (t.category && t.category.toLowerCase().includes(filter.toLowerCase()))
  );

  const formatCurrency = (val: number) => {
    const isNegative = val < 0;
    const formatted = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(Math.abs(val));
    return isNegative ? `-${formatted}` : formatted;
  };

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full relative">
      <div className="p-6 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <h3 className="text-lg font-bold text-slate-800">Histórico Consolidado</h3>
        <div className="relative">
          <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm"></i>
          <input 
            type="text" 
            placeholder="Filtrar por descrição..."
            className="pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/20 w-full sm:w-64"
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto overflow-y-visible">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-slate-500">
            <tr>
              <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-widest">Data</th>
              <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-widest">Fonte</th>
              <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-widest">Descrição</th>
              <th className="px-6 py-4 font-bold uppercase text-[10px] tracking-widest text-right">Valor</th>
              <th className="px-6 py-4 w-10"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filtered.length > 0 ? filtered.map((t) => {
              const isIgnored = ignoredIds.includes(t.id);
              return (
                <tr 
                  key={t.id} 
                  className={`transition-colors relative group ${isIgnored ? 'bg-slate-50 text-slate-400 opacity-60 italic line-through' : 'hover:bg-slate-50/50'}`}
                >
                  <td className="px-6 py-4 whitespace-nowrap text-[12px]">
                    {t.date}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`text-[9px] font-black px-2 py-0.5 rounded-md uppercase tracking-tighter ${
                      isIgnored 
                        ? 'bg-slate-200 text-slate-500' 
                        : t.source === 'manual' 
                          ? 'bg-amber-100 text-amber-700' 
                          : t.source.includes('nubank') 
                            ? 'bg-purple-100 text-purple-700' 
                            : 'bg-emerald-100 text-emerald-700'
                    }`}>
                      {t.source === 'manual' ? t.manualSourceLabel : SOURCE_LABELS[t.source]}
                    </span>
                  </td>
                  <td className="px-6 py-4 font-medium max-w-xs truncate text-[13px]">
                    {t.description}
                  </td>
                  <td className={`px-6 py-4 text-right font-bold text-[13px] ${isIgnored ? 'text-slate-400' : t.type === 'income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                    {t.type === 'income' && !isIgnored ? '+' : ''} {formatCurrency(t.amount)}
                  </td>
                  <td className="px-6 py-4 text-right relative">
                    <button 
                      onClick={() => setOpenMenuId(openMenuId === t.id ? null : t.id)}
                      className="p-1 hover:bg-slate-200 rounded-lg text-slate-400 transition-all"
                    >
                      <i className="fas fa-ellipsis-v"></i>
                    </button>
                    {openMenuId === t.id && (
                      <>
                        <div className="fixed inset-0 z-10" onClick={() => setOpenMenuId(null)}></div>
                        <div className="absolute right-6 top-10 bg-white border border-slate-200 rounded-xl shadow-xl py-2 w-48 z-20 animate-in fade-in zoom-in-95 duration-100">
                          <button 
                            onClick={() => {
                              onEdit(t);
                              setOpenMenuId(null);
                            }}
                            className="w-full px-4 py-2 text-left text-xs font-bold hover:bg-slate-50 flex items-center gap-2 transition-colors border-b border-slate-100 pb-2 mb-1"
                          >
                            <i className="fas fa-edit text-indigo-500"></i>
                            Editar Lançamento
                          </button>
                          <button 
                            onClick={() => {
                              onToggleIgnore(t.id);
                              setOpenMenuId(null);
                            }}
                            className="w-full px-4 py-2 text-left text-xs font-bold hover:bg-slate-50 flex items-center gap-2 transition-colors"
                          >
                            <i className={isIgnored ? "fas fa-check-circle text-emerald-500" : "fas fa-eye-slash text-slate-500"}></i>
                            {isIgnored ? 'Reconsiderar' : 'Desconsiderar'}
                          </button>
                        </div>
                      </>
                    )}
                  </td>
                </tr>
              );
            }) : (
              <tr>
                <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                  Nenhuma transação encontrada.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TransactionList;

import React, { useState, useEffect } from 'react';
import { Transaction, SourceKey } from '../types';

interface ManualEntryModalProps {
  onClose: () => void;
  onAdd: (tx: Transaction) => void;
  editTransaction?: Transaction | null;
}

const ManualEntryModal: React.FC<ManualEntryModalProps> = ({ onClose, onAdd, editTransaction }) => {
  const [date, setDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [sourceLabel, setSourceLabel] = useState('Dinheiro');
  const [type, setType] = useState<'income' | 'expense'>('expense');

  useEffect(() => {
    if (editTransaction) {
      const [d, m, y] = editTransaction.date.split('/');
      setDate(`${y}-${m}-${d}`);
      setDescription(editTransaction.description);
      setAmount(Math.abs(editTransaction.amount).toString());
      setSourceLabel(editTransaction.manualSourceLabel || 'Dinheiro');
      setType(editTransaction.type);
    }
  }, [editTransaction]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    const numAmount = Math.abs(parseFloat(amount));
    const finalAmount = type === 'expense' ? -numAmount : numAmount;

    const newTx: Transaction = {
      id: editTransaction ? editTransaction.id : `manual-${Date.now()}`,
      date: date.split('-').reverse().join('/'),
      description: description,
      amount: finalAmount,
      category: editTransaction?.category || 'Manual',
      type: type,
      source: editTransaction ? editTransaction.source : 'manual',
      manualSourceLabel: sourceLabel
    };

    onAdd(newTx);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden animate-in slide-in-from-bottom-4 duration-300">
        <form onSubmit={handleSubmit}>
          <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
            <div>
              <h3 className="text-xl font-bold text-slate-800">{editTransaction ? 'Editar Lançamento' : 'Novo Lançamento'}</h3>
              <p className="text-sm text-slate-500">{editTransaction ? 'Ajuste os dados da transação' : 'Adicione um gasto ou ganho manual'}</p>
            </div>
            <button type="button" onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2">
              <i className="fas fa-times text-xl"></i>
            </button>
