                  <td className="px-6 py-4 text-right relative overflow-visible">
                    <div className="relative inline-block text-left">
                      <button 
                        onClick={() => setOpenMenuId(openMenuId === t.id ? null : t.id)}
                        className="p-1.5 hover:bg-slate-200 rounded-lg text-slate-400 transition-all focus:outline-none"
                      >
                        <i className="fas fa-ellipsis-v"></i>
                      </button>

                      {openMenuId === t.id && (
                        <>
                          <div className="fixed inset-0 z-[60]" onClick={() => setOpenMenuId(null)}></div>
                          <div className="absolute right-0 mt-2 w-48 bg-white border border-slate-200 rounded-xl shadow-2xl z-[70] py-2 animate-in fade-in zoom-in-95 duration-150">
                            <button 
